-- Deactivate old fake defaults (keep rows, just hide them from the UI)
UPDATE default_topics  SET is_active = FALSE WHERE id::text LIKE '11111111-%';
UPDATE default_presets SET is_active = FALSE WHERE id::text LIKE '22222222-%';

-- ============================================================================
-- DEFAULT TOPICS
-- ============================================================================
ON CONFLICT (name) DO UPDATE
  SET description = EXCLUDED.description,
      questions = EXCLUDED.questions,
      display_order = EXCLUDED.display_order,
      is_active = TRUE;

-- ============================================================================
-- DEFAULT PRESETS
-- ============================================================================
ON CONFLICT (name) DO UPDATE
  SET description = EXCLUDED.description,
      topic_ids = EXCLUDED.topic_ids,
      display_order = EXCLUDED.display_order,
      is_active = TRUE;

