INSERT INTO default_topics (id, name, description, questions, display_order, is_active)
VALUES
    ('33333333-0000-0000-0000-000000000001', 'Ice Breakers', 'An easy, no-pressure warm-up to find some common ground fast.', '["What''s one small thing that quietly made your day better recently?","If you could have any superpower for one day, what would it be?","What''s the most random or useless skill you happen to have?","What''s something you''re a little too excited about right now?","If you could teleport somewhere this second, where would you land?","What’s something you always carry with you?","What’s a smell that instantly brings back memories?","What''s a show, song, or snack you love but would never admit to in public?","If your life were a movie, what would the title be?","What''s a fun fact about you that catches people off guard?","What''s the best compliment a stranger has ever given you?","If you could instantly be great at one thing, what would you pick?","What’s one thing you can’t start your day without?","Is there something that you find weirdly satisfying?","What’s your favorite comfort food?","What’s one thing you’re currently obsessed with?","What''s a question you wish people asked you more often?"]'::jsonb, 1, TRUE),
    ('33333333-0000-0000-0000-000000000002', 'Daily Life', 'The little rhythms and routines that quietly shape who we are.', '["What’s the first thing you do after waking up?","What’s your favorite part of your daily routine?","How do your weekends usually unfold when no one''s watching?","What''s a habit you built that you''re genuinely proud of?","Are you a morning person or a night owl, and has that always been true?","What''s the meal you make when you can''t be bothered to think?","What''s a sound that''s just part of the soundtrack of your daily life?","If you could remove one chore, what would it be?","How do you relax after a long day?","What''s one ordinary thing you''d genuinely miss if it disappeared?","Do you use to-do lists or just go with the flow?","What do you love, or quietly tolerate, about where you live?","What’s one simple joy that never fails to make you smile?","Do you like planning or being spontaneous with your day?","What does your perfect Sunday look like?"]'::jsonb, 2, TRUE),
    ('33333333-0000-0000-0000-000000000003', 'Dreams & Ambitions', 'The things you''re quietly chasing, and what keeps you going.', '["What’s a dream you’ve had since childhood that still inspires you?","What’s one thing that keeps you motivated when things get hard?","Who has influenced your ambitions the most in life?","Do you believe in setting big goals or small achievable ones?","What would you go after tomorrow if you knew you couldn''t fail?","When something finally goes right for you, how do you celebrate it?","What''s a goal you''ve already hit that still makes you a proud?","How do you handle setbacks when chasing your dreams?","What’s something you’ve always wanted to learn but haven’t yet?","How do you define success?","Is there a version of your life you sometimes daydream about?","If you could achieve one major goal this year, what would it be?","Who do you look up to as a role model for ambition?","Do you prefer dreaming big or being realistic?","If your younger self saw where you''re headed, what would surprise them?"]'::jsonb, 3, TRUE),
    ('33333333-0000-0000-0000-000000000004', 'Travel & Wandering', 'Places you''ve loved, trips that stuck with you, and where you''re itching to go.', '["What''s the most unforgettable place you''ve ever visited?","Do you prefer mountains, beaches, or cities?","What’s your dream travel destination?","Have you ever experienced culture shock while traveling?","What''s a dish you tried abroad that you still think about?","Do you enjoy solo travel or group adventures more?","What''s the most unexpected thing that''s ever happened to you on a trip?","If you had to live somewhere new for a year, where would you pick?","What’s your favorite way to document travel memories?","Do you prefer planning every detail or exploring freely?","What’s one travel tip you’d give to anyone?","What''s one travel lesson you learned the hard way?","Have you ever made a real connection with someone while traveling?","What’s one place you’d love to visit again?","What''s the one thing you always pack, no matter how short the trip?","If money and time vanished as problems, where are you going for a month?","What’s the next place on your travel bucket list?"]'::jsonb, 4, TRUE),
    ('33333333-0000-0000-0000-000000000005', 'Hobbies', 'The things you do for no reason other than they light you up.', '["What makes you lose track of time?","What’s something you’ve always wanted to try?","What activity makes you feel most like the real you?","Do you prefer hobbies that relax you or energize you?","What''s the most unusual thing you''ve ever tried just for fun?","Do you collect anything interesting?","Has a hobby ever made you money?","What''s one thing you think everyone should try at least once?","What’s the most unusual hobby you’ve heard of?","Do you like outdoor or indoor activities more?","Who introduced you to your current favorite hobby?","What’s something you’re passionate about but rarely talk about?","Is there something you do that would surprise other people who know you?","What''s something you''d happily teach someone else?","What hobby makes you feel happiest when you do it?","What would you pick up tomorrow if money and time weren''t a factor?","What do you admire others doing but have never dared try yourself?"]'::jsonb, 5, TRUE),
    ('33333333-0000-0000-0000-000000000006', 'Food & Flavor', 'Comfort dishes, food memories, and the flavors that mean something.', '["What’s your comfort food when you’re feeling down?","Which country’s cuisine do you enjoy the most?","What''s the strangest thing you''ve ever willingly eaten?","Do you like cooking, or do you prefer dining out?","Best street food joint in your town?","What’s your favorite meal of the day?","Do you prefer sweet or savory snacks?","What food or smell teleports you straight back to childhood?","What’s your go-to comfort drink or beverage?","If you could learn one international recipe, which would it be?","You can only eat ONE meal for the rest of your life. What is it?","Do you like to experiment with new flavors or stick to favorites?","What food trend genuinely baffles you?","What dish means ''celebration'' in your world?","If you could share one meal with anyone in history, who would it be?"]'::jsonb, 6, TRUE),
    ('33333333-0000-0000-0000-000000000007', 'Childhood Memories', 'The early moments and small worlds that quietly built who you are.', '["What’s your earliest memory as a child?","What was your favorite game or toy growing up?","Who was your childhood best friend and what did you do together?","What’s one cartoon or show you loved as a kid?","Did you have a favorite place to play outdoors?","What food or smell reminds you of your childhood?","What''s something you fully believed as a kid that''s hilarious now?","What''s the funniest thing you ever did as a child?","What did you want to be when you grew up, and how''d that age?","Who in your family did you look up to most as a kid?","What’s one childhood tradition your family had?","What music or song takes you back to your early years?","What did your childhood self get right about life that adults forget?","What’s one lesson you learned early in life that stayed with you?","If you could relive one day from your childhood, which would it be?"]'::jsonb, 7, TRUE),
    ('33333333-0000-0000-0000-000000000008', 'Funny & Unexpected', 'Light, spontaneous, and ready for a laugh.', '["What’s the funniest thing that’s ever happened to you?","Have you ever laughed at the worst possible moment?","What''s a weird superstition you secretly half-believe?","Have you ever had an embarrassing autocorrect fail?","What’s your go-to funny story to tell people?","What’s the most awkward situation you’ve ever been in?","Ever waved at a total stranger thinking they were someone else?","What’s a phrase or word you always mispronounced as a kid?","If you could play a harmless prank on someone, what would it be?","What’s the weirdest thing you’ve seen in public?","When did a plan go so wrong it became a great story?","Have you ever laughed so hard you cried?","What''s a slightly ridiculous habit you have?","What’s the silliest misunderstanding you’ve ever had?","What movie or show scene never fails to make you laugh?"]'::jsonb, 8, TRUE),
    ('33333333-0000-0000-0000-000000000009', 'Movies, Music & Media', 'The films, shows, and music that have lodged themselves in you.', '["What''s a song you''d play to introduce someone to your taste?","What’s a movie you can watch over and over again?","Who’s your favorite musician or band of all time?","What’s the first concert you ever attended?","What TV show character do you relate to most?","What kind of music helps you focus or relax?","What’s a song that brings back strong memories for you?","Do you prefer watching movies in theaters or at home?","Which movie soundtrack do you think is perfect?","What’s the most inspiring documentary you’ve seen?","If your life had a theme song, what would it be?","Podcasts, audiobooks, or silence, what fills your in-between moments?","What’s the funniest movie you’ve ever seen?","Which actor or actress do you like the most?","What’s your all-time favorite animated movie?","What''s the best song of all time?","What kind of music would you play during a road trip?"]'::jsonb, 9, TRUE),
    ('33333333-0000-0000-0000-000000000010', 'Creativity & Imagination', 'Where your ideas come from and what you''d make if nothing held you back.', '["What inspires your creativity the most?","If you could invent anything, what would it be?","Do you express yourself best through words, images, sound, or something else?","What’s the most creative idea you’ve ever had?","Do you get your best ideas in the morning or late at night?","If imagination were a superpower, how would you use it?","What would you make if you knew no one would ever judge it?","Do you believe creativity can be learned or is it natural?","If you could live inside a fictional world, which would it be?","What’s a creative project you’ve always wanted to start?","Do you prefer spontaneous creativity or structured planning?","What color or sound best represents your imagination?","Who''s the most creative person you''ve ever met, and what made them that way?","What kind of art form do you wish you could master?","How do you find inspiration when you feel stuck creatively?","Where do you think original ideas actually come from?"]'::jsonb, 10, TRUE),
    ('33333333-0000-0000-0000-000000000011', 'Technology & The Future', 'Gadgets, AI, and the strange world that''s rushing toward us.', '["What piece of technology could you not live without?","Do you think AI will make life easier or more complicated?","What’s a futuristic invention you wish already existed?","How has technology changed the way you connect with people?","Do you prefer digital or physical tools for creativity?","What’s one VERY old-fashioned thing you still enjoy doing?","How do you balance screen time with real-life experiences?","What innovation from the last decade genuinely amazed you?","Would you ever want to live in a smart home?","What’s a piece of tech you think will be obsolete soon?","Do you think robots will ever replace teachers or doctors?","How would you feel about an AI that knew you better than your friends do?","What''s your honest take on virtual and augmented reality?","Do you trust self-driving cars? Why or why not?","What do you hope the world will look like in 50 years?","What''s one thing you hope technology never replaces?","Where do you draw the line on letting machines make decisions for us?"]'::jsonb, 11, TRUE),
    ('33333333-0000-0000-0000-000000000012', 'Work & Education', 'What you''ve picked up from work, school, and everything in between.', '["What was your first job, and what did it teach you?","Do you prefer working in a team or on your own?","What motivates you to do your best at work or school?","What’s the most useful skill you’ve ever learned?","Do you enjoy learning new things or sticking to what you know?","Was there a teacher or mentor who genuinely changed your trajectory?","What’s one piece of advice you’d give to your younger self?","What kind of environment lets you do your best thinking?","Do you learn better by doing or by understanding the theory first?","How do you handle challenges in work or study?","What''s a mistake at work or school that taught you more than any success?","What''s something you''re better at than you give yourself credit for?","How do you keep going when the work turns repetitive?","In the end, do you think experience or credentials matter more?","What''s a skill you think will be essential ten years from now?"]'::jsonb, 12, TRUE),
    ('33333333-0000-0000-0000-000000000013', 'Values & Beliefs', 'The principles that quietly steer your choices and shape who you are.', '["What''s one value you genuinely try to live by, even when it''s hard?","How do you define integrity in your life?","What''s something you believe that the people around you might not?","How do you decide what’s right or wrong in difficult situations?","Do you think people are naturally good or shaped by experience?","What’s one belief that has changed for you over time?","How do you react when someone challenges something you hold dear?","What does kindness actually look like in action, not theory?","Is honesty always the right call, or does it depend?","Who had the biggest hand in shaping your sense of right and wrong?","What''s a line you''d never cross, whatever the cost?","How do you show gratitude in daily life?","Do you think empathy can be taught, or do you either have it or not?","How do you define respect in relationships and society?","What do you think gives life meaning?","Is it more important to be honest or to be kind, when you can''t be both?"]'::jsonb, 13, TRUE),
    ('33333333-0000-0000-0000-000000000014', 'Society & Culture', 'How people live, connect, and change across the world.', '["What’s one thing you love about your culture?","Do you think globalization helps or harms local traditions?","How has social media changed the way we interact as a society?","What cultural festival or tradition do you find fascinating?","How do you think diversity enriches communities?","Do you believe technology brings people closer or apart?","What''s a social issue you find hard to stay quiet about?","How do you think art influences society?","What cultural difference has surprised you the most?","How does your generation differ from the ones before it?","What language or custom would you love to learn more about?","How do you think travel changes people’s worldviews?","What’s something from another culture you’ve adopted?","How do humor and storytelling differ between cultures?","Do you think the world is becoming more connected or divided?"]'::jsonb, 14, TRUE),
    ('33333333-0000-0000-0000-000000000015', 'Deep Reflections', 'The quieter questions about who we are and why we do what we do.', '["What moment in your life changed you the most?","Do you believe people can truly change?","What do you think makes a person “good”?","How do you usually deal with uncertainty in life?","What do you think happens when we die?","What’s one lesson life keeps teaching you over and over?","How do you define peace of mind?","What makes you feel most alive?","Do you think happiness is a choice or a result?","What does “home” mean to you?","How do you find the balance between your head and your heart?","What’s a truth about yourself you discovered recently?","Is forgiveness something that comes easily to you, or is it work?","What part of who you are took you the longest to accept?","What would you want someone to remember about you?","What''s a fear you''ve quietly made peace with?","If you could ask your future self one question, what would it be?"]'::jsonb, 15, TRUE),
    ('33333333-0000-0000-0000-000000000016', 'Nature & Environment', 'Your connection to the natural world and the planet we share.', '["What’s your favorite place in nature to relax or think?","How much of your week actually happens outdoors?","Forests, oceans, or mountains, which one is yours?","What natural sound calms you the most?","Do you believe individuals can make a real environmental difference?","What’s one eco-friendly habit you practice regularly?","Have you ever had a memorable encounter with wildlife?","How do you feel when you disconnect from technology and go outside?","What season best reflects your personality?","What’s a natural wonder you’d love to see in person?","Have you ever spent a night literally under the stars - no tent, no bed?","Could you actually live off-grid, or is that just a nice daydream?","How do you feel about climate change - hopeful or worried?","What’s one thing cities could do to become greener?","What do you appreciate most about the natural world?"]'::jsonb, 16, TRUE),
    ('33333333-0000-0000-0000-000000000017', 'Games & Challenges', 'Quick challenges, friendly competition, and playful hypotheticals.', '["What’s your favorite game to play with friends?","Are you fiercely competitive or genuinely just there for the fun?","What’s the hardest challenge you’ve ever completed?","If we were in a trivia contest, what topic would you dominate?","Would you rather win every game or have fun even when you lose?","What skill would you love to be unbeatable at?","Do you enjoy board games, video games, or outdoor games more?","Hit me with a friendly challenge, right here, right now.","Have you ever lost a game but still felt proud?","What''s the most ridiculous dare you''ve ever actually done?","What riddle or brain-teaser has stumped you the longest?","Do you enjoy escape rooms or puzzle-solving activities?","What’s your strategy when playing games - luck or logic?","If you could create your own game, what would it be like?","What’s a personal challenge you’ve set for yourself recently?"]'::jsonb, 17, TRUE),
    ('33333333-0000-0000-0000-000000000018', 'Mysteries & Unknowns', 'Dreams, space, coincidences, and the things we can''t quite explain.', '["Do you believe in fate or coincidence?","Have you ever had a dream that felt strangely real?","What’s a mystery from history you’d like solved?","Do you believe in extraterrestrial life?","When was the last time déjà vu genuinely unsettled you?","What’s something you find fascinating but can’t explain?","Do you believe in intuition or gut feelings?","What’s a conspiracy theory you find entertaining (not necessarily true)?","How do you think the universe began?","What’s your opinion on ghosts or the afterlife?","Have you ever had a coincidence that felt almost designed?","What part of science still feels like magic to you?","Given the chance, would you actually go to space?","Do you think we’ll ever truly understand consciousness?","What''s one answer you''d trade almost anything to know for certain?"]'::jsonb, 18, TRUE),
    ('33333333-0000-0000-0000-000000000019', 'Philosophy & Life Questions', 'The big ''why'' questions about meaning, existence, and being human.', '["Do you believe everything happens for a reason, or is life random?","What’s more important - happiness or purpose?","Do you think people are born good or become good through choices?","What makes a life meaningful?","If our time is genuinely limited, how should we be spending it?","Do you believe in free will or destiny?","What’s one philosophy or quote that guides you?","Can two people ever truly understand each other''s inner experience?","What does “truth” mean to you?","Is morality universal, or does it bend with culture?","What’s something humans still don’t understand about life?","Would life have meaning without challenges?","Do you believe happiness is the goal of life?","What’s one belief that gives you strength?","If you could know the answer to one unanswerable question, which?"]'::jsonb, 19, TRUE),
    ('33333333-0000-0000-0000-000000000020', 'Connection & Friendship', 'Trust, closeness, and what makes the bonds between people hold.', '["What do you value most in a friend?","How do you usually show appreciation to people you care about?","Do you believe opposites attract in friendships or relationships?","What’s the best piece of relationship advice you’ve ever received?","How do you handle conflict in a healthy way?","What’s a small act of kindness that made a big impact on you?","How do you maintain long-distance friendships?","Do you think trust can be rebuilt once it’s broken?","What do you think makes someone a good listener?","What''s something a friend taught you that you never expected?","What''s your ''love language'' with friends and family?","How do you balance giving and receiving in relationships?","Who in your life do you feel you can be 100% yourself around?","Do you think friendships can last a lifetime?","What kind of people do you naturally connect with?"]'::jsonb, 20, TRUE),
    ('33333333-0000-0000-0000-000000000021', 'Love & Attraction', 'Lightly romantic, flirty, and curious, with care.', '["What’s your idea of a perfect first date?","Do you believe in love at first sight?","What’s the most romantic gesture you’ve ever made or received?","How do you usually show affection?","What kind of personality traits attract you the most?","Do you think opposites can make great couples?","What’s one thing that instantly makes someone more attractive?","How would you define real love, past the butterflies?","Do you prefer subtle flirting or direct honesty?","What’s a small gesture that always wins your heart?","Tell me about a romantic moment that was more funny than smooth.","What song or film comes closest to how you see love?","Do you believe people can fall in love online?","What’s your biggest “green flag” and what''s your biggest \"red flag\" in a someone?","What kind of date would make you say “wow, that was special”?"]'::jsonb, 21, TRUE),
    ('33333333-0000-0000-0000-000000000022', 'Happiness & Mindset', 'What makes you feel grounded, hopeful, and genuinely well.', '["What does happiness mean to you personally?","What small things make your day brighter?","How do you usually lift your mood when you’re feeling down?","Does your happiness come from inside you, or from the people around you?","What’s a daily habit that helps you stay positive?","How do you practice gratitude in your life?","Who or what makes you laugh the most?","Are you happier with a reliable routine or a steady stream of surprises?","What’s something that instantly relaxes you?","How do you usually celebrate your small wins?","What single shift in thinking improved your life the most?","Do you think it’s possible to be happy all the time?","What’s a hobby or activity that gives you peace?","Where do you find hope when things genuinely feel hard?","What’s one piece of advice that always lifts your spirits?"]'::jsonb, 22, TRUE),
    ('33333333-0000-0000-0000-000000000023', 'Challenges & Growth', 'How we handle the hard parts, and grow through them.', '["What’s the biggest challenge you’ve ever overcome?","How do you usually react when things don’t go as planned?","What difficult experience ended up teaching you the most?","Do you believe failure is necessary for success?","How do you stay motivated during tough times?","Tell me about a mistake that quietly turned into a gift.","How do you usually get out of your comfort zone?","What’s one fear you’ve faced and conquered?","Do you prefer steady progress or big leaps of change?","How do you define personal growth?","What advice would you give someone going through a hard time?","What part of you is stronger now than it was a few years ago?","How do you handle criticism - does it motivate or discourage you?","What’s something you’ve learned about yourself recently?","What challenge are you currently working to overcome?"]'::jsonb, 23, TRUE),
    ('33333333-0000-0000-0000-000000000024', 'Books & Ideas', 'Reading, learning, and the ideas that rewire how you see things.', '["What’s a book that changed the way you think?","Do you prefer fiction or non-fiction, and why?","Who’s an author that inspires you?","What’s a book you wish everyone would read?","How do you usually choose what to read next?","Do you prefer physical books or e-books?","What’s the most surprising thing you’ve ever learned?","Have you ever reread a book because you missed it?","What topic could you read about endlessly without getting bored?","How do you turn what you read into something you actually use?","What’s a quote or idea that stayed with you for years?","Do you like discussing books with others or reading alone?","What’s the last thing you learned that amazed you?","Do you believe knowledge should always be free to access?","If you could write a book, what would it be about?"]'::jsonb, 24, TRUE),
    ('33333333-0000-0000-0000-000000000025', 'Cultural Exchange', 'Traditions, customs, and the differences that make people fascinating.', '["What’s a tradition in your culture that you’re proud of?","Have you ever experienced another culture firsthand?","What cultural custom from another place do you admire?","How do you celebrate important holidays or events?","What’s something unique about your country that others find surprising?","How do you greet people in your culture?","Have you ever taught a foreigner about your traditions?","What’s a festival or holiday you’d like to experience abroad?","Do you think cultural differences bring people closer or divide them?","What’s a piece of music, art, or food that represents your culture best?","What’s a stereotype about your culture that isn’t true?","Have you ever had a funny cultural misunderstanding?","What tradition would you like to start in your own life?"]'::jsonb, 25, TRUE),
    ('33333333-0000-0000-0000-000000000026', 'Fantasy Worlds & Superpowers', 'Powers, magic, and the gloriously impossible.', '["If you could have any superpower, what would it be and why?","Would you rather fly or be invisible?","What fantasy world would you love to live in?","If you could time travel, which era would you visit?","What would your superhero name be?","Would you rather have magical powers or futuristic technology?","If you could rewrite one rule of reality, what would it be?","Who would be your sidekick if you were a superhero?","Would you rather explore space or the ocean’s depths?","Which mythical creature has always fascinated you?","If dreams could come to life for one day, what would you dream?","What kind of villain would you be in a movie?","Would you rather control time, weather, or minds?","What’s one power that might secretly be a curse?","If you could create your own fantasy world, what would it look like?"]'::jsonb, 26, TRUE),
    ('33333333-0000-0000-0000-000000000027', 'Art & Expression', 'How people put what''s inside them out into the world.', '["What’s your favorite form of art - music, painting, film, or something else?","Do you enjoy visiting museums or art galleries?","What’s a song or artwork that deeply moved you?","Do you think everyone has a creative side?","Beyond the obvious, how do you express what you''re feeling?","Is there a piece of art you''ve never been able to forget?","Do you think art should always have a message?","How does music affect your emotions?","What kind of art form do you wish you could master?","Who’s an artist or creator that inspires you?","Do you prefer modern or classical art styles?","Have you ever created something that made you proud?","Do you think fashion is a form of self-expression?","What’s your favorite color combination and why?","How would you describe your personal aesthetic or style?"]'::jsonb, 27, TRUE),
    ('33333333-0000-0000-0000-000000000028', 'Time & Memory', 'How moments shape us and how time keeps quietly rewriting them.', '["What’s a memory that always makes you smile?","Do you think time heals all wounds?","How do you usually preserve your favorite memories?","What moment in your life felt like it lasted forever?","Would you rather revisit the past or see the future?","What smell or sound instantly takes you back in time?","Do you think memories change over time?","What’s a lesson from your past that you still live by?","If you could relive one year of your life, which would it be?","How do you think aging changes perspective?","What’s something you miss from your childhood?","Do you prefer remembering or imagining?","When did you most wish you could just slow time down?","What helps you stay present instead of living in the past?","What kind of memories do you want to create in the next year?"]'::jsonb, 28, TRUE),
    ('33333333-0000-0000-0000-000000000029', 'Future Society', 'Where humanity might be heading, and what''s at stake.', '["How do you think daily life will change 100 years from now?","What role do you think AI will play in future societies?","Do you believe humans will colonize other planets?","What traditions do you hope will survive in the future?","How do you imagine education will look in 50 years?","Do you think work-life balance will improve or decline in the future?","What’s one futuristic idea that excites you most?","How do you think relationships will evolve with technology?","What’s a risk humanity should be more aware of?","Do you think robots should have rights?","How do you think art and creativity will change in the future?","What’s one invention that could make society better?","How would you describe an ideal world 200 years from now?","Do you think future generations will value privacy?","What’s your biggest hope for humanity’s future?"]'::jsonb, 29, TRUE),
    ('33333333-0000-0000-0000-000000000030', 'Random Curiosities', 'A grab-bag of weird, surprising, and delightfully pointless questions.', '["If a language could just download into your brain, which one?","What’s a random skill you wish you had?","Would you rather talk to animals or speak every human language?","What’s the weirdest thing you’ve Googled lately?","If you could swap lives with someone for a week, who would it be?","What’s something small that fascinates you about the world?","If aliens visited Earth, what’s the first thing you’d show them?","What’s the most unusual talent you’ve ever seen?","Would you rather live underwater or in space?","What’s a fun “what if” scenario you like to imagine?","If you could invent a new holiday, what would it celebrate?","What’s a random question you’ve always wanted answered?","What’s your favorite useless fact?","If you could bend one rule of reality, what would you change?","What’s something you find fascinating for no logical reason?"]'::jsonb, 30, TRUE),
    ('33333333-0000-0000-0000-000000000031', 'Career', 'Your work journey, the lessons, and where you''re headed.', '["What inspired you to choose your current career path?","What’s one skill from your job that you use in everyday life?","What do people most misunderstand about what you do?","What’s a career accomplishment you’re proud of?","What’s the best career advice you’ve ever received?","What kind of work environment helps you thrive?","What career would you choose if you could start over?","What’s something new you’d like to learn for your career?","What do you think the future of your industry will look like?","What’s one challenge you often face at work?","How has your definition of career success changed over time?","Do you prefer stability or exploring new opportunities?","What’s something your younger self would be proud of today?","What’s a project that challenged you but helped you grow?"]'::jsonb, 31, TRUE),
    ('33333333-0000-0000-0000-000000000032', 'Business & Hustle', 'Lessons and instincts about building, leading, and betting on ideas.', '["What’s the best business advice you’ve ever received?","What’s the biggest mistake entrepreneurs often make?","What business skill do you think everyone should have, founder or not?","What did a failure teach you that a win never could?","Do you think passion or strategy matters more in business?","What’s one thing you wish you knew before starting a business?","How do you decide whether an idea is worth pursuing?","What’s the best way to build a strong professional network?","What do you think makes a great leader in business?","How do you approach making difficult business decisions?","What trend do you think most people are sleeping on?","Beyond money, how do you measure whether something''s working?","What lesson does almost everyone in business learn eventually, the hard way?","What would you tell someone on day one of their first venture?","What’s the best way to stay motivated in entrepreneurship?"]'::jsonb, 32, TRUE),
    ('33333333-0000-0000-0000-000000000033', 'Money & Investing', 'Smart decisions, risk, and thinking long-term with money.', '["What''s the one rule you won''t break with your money?","Do you prefer long-term investing or short-term strategies?","What’s a common investing myth you think people should stop believing?","What’s a financial lesson you learned the hard way?","How do you decide whether an investment is worth the risk?","What''s your thinking on not putting all your eggs in one basket?","What sector or industry do you believe has a strong future?","Do you think investing early matters more than investing big?","What’s your opinion on real estate as an investment?","What’s a risk you took that paid off?","Do you watch the markets closely or set it and forget it?","How do you balance playing it safe against seizing a chance?","What money mistake do you wish you could warn everyone about?","What’s a financial goal you''re working toward right now?","In the end, does knowledge or instinct matter more with money?"]'::jsonb, 33, TRUE),
    ('33333333-0000-0000-0000-000000000034', 'Politics & Society', 'Ideas, values, and disagreement, approached with curiosity and respect.', '["Do you think people can disagree politically and still be good friends?","What values do you think are most important for a society to thrive?","Do you believe voting makes a real difference?","How do you usually stay informed about world events?","What political value do you consider most fundamental - freedom, equality, or justice?","Do you believe political discussions should be taught in schools?","What’s a political issue you think people should talk about more often?","What’s one thing that helps you understand different political viewpoints?","Do you think the world is becoming more politically divided or united?","What role should citizens play in shaping their communities?","What political topic do you think young people care about most?","How do you decide which sources of information you trust?","What political idea do you think will be more important in the next decade?","Should politicians be held to higher moral standards than others?","What makes political conversations either productive or unproductive?"]'::jsonb, 34, TRUE),
    ('33333333-0000-0000-0000-000000000035', 'Fun Facts', 'Surprising, quirky, and delightfully shareable bits of knowledge.', '["What’s a random fact you recently learned that amazed you?","What’s a fun fact about your country or culture?","What’s a weird animal fact you love?","What’s one skill or talent you have that people find surprising?","What’s a little-known fact about yourself?","What’s a mind-blowing science fact you enjoy?","What’s a historical fact you think everyone should know?","What’s a fact about your profession that surprises people?","What’s a strange coincidence from your life?","What’s a cool fact about nature you’ve learned?","What’s a historical event you find fascinating?","What’s a fact about space that you enjoy thinking about?","What’s a fact that always shocks people when you tell them?","What’s something you know that seems unbelievable but is true?","What’s your favorite fun fact about the human body?"]'::jsonb, 35, TRUE),
    ('33333333-0000-0000-0000-000000000036', 'Would You Rather', 'Two options, one choice, and surprisingly revealing every time.', '["Would you rather travel the world for free or have unlimited free food for life?","Would you rather be able to speak every language or talk to animals?","Would you rather always be 10 minutes late or 20 minutes early?","Would you rather live by the ocean or in the mountains?","Would you rather never have to sleep or never have to eat?","Would you rather teleport anywhere or read minds?","Would you rather give up music or movies forever?","Would you rather explore space or explore the deep ocean?","Would you rather always know the truth or always make people happy?","Would you rather live without the internet or without air conditioning?","Would you rather win the lottery or live twice as long?","Would you rather be able to pause time or rewind time?","Would you rather always travel by plane or always travel by train?","Would you rather live without caffeine or without sugar?","Would you rather have a rewind button or a fast-forward button for your life?"]'::jsonb, 36, TRUE),
    ('33333333-0000-0000-0000-000000000037', 'Bucket List Items', 'The goals, dreams, and experiences you''re saving up for someday.', '["What''s sitting at the very top of your bucket list?","What country or city do you dream of visiting someday?","What’s an experience you want to have at least once in life?","What skill would you love to truly master in your lifetime?","What adventure activity would you try if fear wasn’t a factor?","What’s a creative project you want to complete someday?","What is a personal milestone you hope to reach in life?","What’s a natural wonder you dream of seeing in person?","What’s something you want to learn purely for fun?","What event in the world would you love to attend?","What challenge do you hope to overcome someday?","What kind of person do you want to become in the future?","What creative dream do you hope to pursue later in life?","What’s an experience you want to share with someone special?","What’s something you’ve already checked off your bucket list?"]'::jsonb, 37, TRUE)
